class InteractionTracker:
    def __init__(self):
        self.interactions = {}
        self.user_data = {}

    def add_user(self, user_id):
        if user_id not in self.user_data:
            self.user_data[user_id] = {'interactions': []}

    def track_interaction(self, user_id, interaction_type, data):
        if user_id not in self.user_data:
            self.add_user(user_id)

        interaction = {
            'type': interaction_type,
            'data': self.anonymize_data(data),
            'timestamp': self.get_current_timestamp()
        }

        self.user_data[user_id]['interactions'].append(interaction)

    def anonymize_data(self, data):
        # Implement hashing or anonymization logic here
        return hash(data)

    def get_current_timestamp(self):
        from datetime import datetime
        return datetime.now().isoformat()

    def get_user_interactions(self, user_id):
        if user_id in self.user_data:
            return self.user_data[user_id]['interactions']
        return []

    def get_all_interactions(self):
        return self.user_data

# Example usage
tracker = InteractionTracker()
tracker.track_interaction('user123', 'rating', {'item_id': 'item456', 'rating': 5})
tracker.track_interaction('user123', 'upload', {'file_name': 'photo.jpg'})
tracker.track_interaction('user456', 'context_modification', {'context_id': 'context789', 'new_value': 'updated'})

print(tracker.get_user_interactions('user123'))
print(tracker.get_all_interactions())

