class InteractionTracker:
    def __init__(self):
        self.interactions = {}
        self.user_data = {}

    def add_user(self, user_id):
        if user_id not in self.user_data:
            self.user_data[user_id] = {
                'likes': [],
                'ratings': [],
                'uploads': [],
                'settings_changes': []
            }

    def track_interaction(self, user_id, interaction_type, interaction_data):
        if user_id not in self.user_data:
            self.add_user(user_id)

        if interaction_type not in self.user_data[user_id]:
            raise ValueError("Invalid interaction type")

        if interaction_type == 'likes':
            self.user_data[user_id]['likes'].append(self._anonymize(interaction_data))
        elif interaction_type == 'ratings':
            self.user_data[user_id]['ratings'].append(self._anonymize(interaction_data))
        elif interaction_type == 'uploads':
            self.user_data[user_id]['uploads'].append(self._anonymize(interaction_data))
        elif interaction_type == 'settings_changes':
            self.user_data[user_id]['settings_changes'].append(self._anonymize(interaction_data))

    def _anonymize(self, data):
        # Simple anonymization by hashing the data
        import hashlib
        return hashlib.sha256(data.encode()).hexdigest()

    def get_user_interactions(self, user_id):
        if user_id not in self.user_data:
            return None
        return self.user_data[user_id]

    def add_interaction_type(self, interaction_type):
        for user_id in self.user_data:
            self.user_data[user_id][interaction_type] = []

