from flask_sqlalchemy import SQLAlchemy
from sqlalchemy.exc import IntegrityError
import hashlib
import os

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///interactions.db'
app.config['SQLALCHEMY_TRACK_MODIFICATIONS'] = False
db = SQLAlchemy(app)

class Interaction(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    user_id = db.Column(db.String(64), nullable=False)
    interaction_type = db.Column(db.String(50), nullable=False)
    data = db.Column(db.Text, nullable=False)

    def __init__(self, user_id, interaction_type, data):
        self.user_id = self.hash_user_id(user_id)
        self.interaction_type = interaction_type
        self.data = data

    @staticmethod
    def hash_user_id(user_id):
        return hashlib.sha256(user_id.encode()).hexdigest()

@app.route('/interact', methods=['POST'])
def interact():
    user_id = request.json.get('user_id')
    interaction_type = request.json.get('interaction_type')
    data = request.json.get('data')

    if not user_id or not interaction_type or not data:
        return jsonify({'error': 'Missing data'}), 400

    new_interaction = Interaction(user_id, interaction_type, data)

    try:
        db.session.add(new_interaction)
        db.session.commit()
        return jsonify({'message': 'Interaction recorded'}), 201
    except IntegrityError:
        db.session.rollback()
        return jsonify({'error': 'Failed to record interaction'}), 500

